module top_module(clk,reset,R,S,Out);input reset, clk, R, S;
	 output Out;
	 reg   unused_dataVal;

	 always @(posedge clk, negedge reset)
		if(!reset)
			unused_dataVal<=0;
		else if(R)
			unused_dataVal<=0;
		else if(S)
			unused_dataVal<=1;
		else 
			unused_dataVal<=unused_dataVal;

		assign Out=unused_dataVal;

	 endmodule
